{{<includeonly>safesubst:</includeonly>#invoke:Unsubst||date=__DATE__|$B=
{{ ambox
| name  = Technical
| subst = <includeonly>{{subst:substcheck}}</includeonly>
| small = {{{small|}}}
| type  = style
| class = ambox-technical
| issue = {{#ifeq:{{{1|}}}|introduction|This article's lead section|This {{{1|article}}}}} '''may be too technical for most readers to understand'''.
| talk  = {{{talk|}}}
| fix   = Please [{{fullurl:{{FULLPAGENAME}}|action=edit}} help improve it] to [[Wikipedia:Make technical articles understandable|make it understandable to non-experts]], without removing the technical details.
| removalnotice = yes
| date  = {{{date|}}}
| cat   = Wikipedia articles that are too technical
| all   = All articles that are too technical
}}
}}<noinclude>{{Documentation}}<!-- Add categories to the /doc subpage and interwikis to Wikidata, not here! --></noinclude>

